def enhanced_heuristic(board: Board, boxes: tuple[Pos, ...]) -> int:
    """Greedy matching + mobility penalty (mirrors Rust enhanced_heuristic)."""
    base = greedy_matching(board, boxes)
    goal_set = frozenset(board.goals)
    box_set = frozenset(boxes)
    penalty = 0
    for bx in boxes:
        if bx in goal_set:
            continue
        blocked = 0
        for dx, dy in DIRECTIONS:
            nb = Pos(bx.x + dx, bx.y + dy)
            if nb in board.walls or nb in box_set:
                blocked += 1
        if blocked >= 3:
            penalty += 10
        elif blocked == 2:
            penalty += 2
    return base + penalty

from __future__ import annotations
import itertools
from collections import deque
from functools import lru_cache

# directions are defined in the solver module; reuse them
DIRECTIONS = [(0, -1), (1, 0), (0, 1), (-1, 0)]  # up, right, down, left


@lru_cache(maxsize=None)
def _dead_squares_cached(
    walls: frozenset,
    goals: tuple,
    width: int,
    height: int,
) -> frozenset:
    """
    Squares from which a box can never be pushed onto a goal
    (computed on an empty board, i.e. ignoring other boxes).
    """
    reachable: set[Pos] = set()
    q: deque[Pos] = deque()

    for g in goals:
        reachable.add(g)
        q.append(g)

    while q:
        b = q.popleft()
        for dx, dy in DIRECTIONS:
            # reverse‑push: box was at nb, player stood at pn, then pushed it to b
            nb = Pos(b.x + dx, b.y + dy)               # previous box position
            pn = Pos(b.x + 2 * dx, b.y + 2 * dy)       # player needed to stand
            if (
                0 <= nb.x < width
                and 0 <= nb.y < height
                and 0 <= pn.x < width
                and 0 <= pn.y < height
                and nb not in walls
                and pn not in walls
                and nb not in reachable
            ):
                reachable.add(nb)
                q.append(nb)

    dead = {
        Pos(x, y)
        for x in range(width)
        for y in range(height)
        if Pos(x, y) not in walls and Pos(x, y) not in reachable
    }
    return frozenset(dead)


def heuristic(board: Board, boxes: tuple[Pos, ...]) -> int:
    """Admissible heuristic: optimal Manhattan matching + simple dead‑square
    detection + a tiny blocking penalty."""
    # 1️⃣ dead‑square detection (adds huge penalty if any box is stuck forever)
    dead = _dead_squares_cached(board.walls, board.goals, board.width, board.height)
    for b in boxes:
        if b not in board.goals and b in dead:
            return 10_000

    # 2️⃣ blocking penalty – a box blocked on ≥3 sides needs at least one push
    box_set = frozenset(boxes)
    penalty = 0
    for b in boxes:
        if b in board.goals:
            continue
        blocked = sum(
            (Pos(b.x + dx, b.y + dy) in board.walls or Pos(b.x + dx, b.y + dy) in box_set)
            for dx, dy in DIRECTIONS
        )
        if blocked >= 3:
            penalty += 1

    # 3️⃣ lower‑bound assignment (optimal for ≤6 boxes, greedy otherwise)
    n = len(boxes)
    if n <= 6:
        best = 10**9
        for perm in itertools.permutations(board.goals, n):
            total = 0
            for b, g in zip(boxes, perm):
                total += b.manhattan(g)
                if total >= best:
                    break
            if total < best:
                best = total
        base = best
    else:
        used = [False] * len(board.goals)
        base = 0
        for b in boxes:
            best_dist = 10**9
            best_i = -1
            for i, g in enumerate(board.goals):
                if used[i]:
                    continue
                d = b.manhattan(g)
                if d < best_dist:
                    best_dist = d
                    best_i = i
            used[best_i] = True
            base += best_dist

    return base + penalty
